 1	import React, { FC, useState } from 'react';
 2	
 3	import NewBadge from '@kubevirt-utils/components/badges/NewBadge/NewBadge';
 4	import { HyperConverged } from '@kubevirt-utils/hooks/useHyperConvergeConfiguration';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { Alert, AlertVariant, Split, SplitItem, Switch } from '@patternfly/react-core';
 7	
 8	import { AUTO_RESOURCE_LIMITS_FEATURE_GATE } from './utils/constants';
 9	import { updateAutoResourceLimitsFeatureGate } from './utils/utils';
10	
11	type AutoComputeCPULimitsProps = {
12	  hyperConvergeConfiguration: [hyperConvergeConfig: HyperConverged, loaded: boolean, error: Error];
13	  newBadge?: boolean;
14	};
15	const AutoComputeCPULimits: FC<AutoComputeCPULimitsProps> = ({
16	  hyperConvergeConfiguration,
17	  newBadge,
18	}) => {
19	  const { t } = useKubevirtTranslation();
20	  const [hco, hcoLoaded] = hyperConvergeConfiguration;
21	  const featureGates = hco?.spec?.featureGates;
22	
23	  const [featureEnabled, setFeatureEnabled] = useState<boolean>(
24	    Boolean(featureGates?.[AUTO_RESOURCE_LIMITS_FEATURE_GATE]),
25	  );
26	  const [error, setError] = useState<Error>();
27	
28	  const onFeatureChange = (switchOn: boolean) => {
29	    updateAutoResourceLimitsFeatureGate(hco, switchOn)
30	      .then(() => setFeatureEnabled(switchOn))
31	      .catch((err) => setError(err.message));
32	  };
33	
34	  return (
35	    <>
36	      <Split>
37	        <SplitItem isFilled>
38	          {t('Auto-compute CPU and memory limits')} {newBadge && <NewBadge />}
39	        </SplitItem>
40	        <SplitItem>
41	          <Switch
42	            id="auto-compute-cpu-limits"
43	            isChecked={featureEnabled}
44	            isDisabled={!hcoLoaded}
45	            onChange={(_, checked: boolean) => onFeatureChange(checked)}
46	          />
47	        </SplitItem>
48	      </Split>
49	      {error && (
50	        <Alert
51	          className="autocompute-cpu-limits__error-alert"
52	          isInline
53	          title={t('Error')}
54	          variant={AlertVariant.danger}
55	        >
56	          {error}
57	        </Alert>
58	      )}
59	    </>
60	  );
61	};
62	
63	export default AutoComputeCPULimits;

